// "use client";
import PopularCategories from "@/app/components/user components/Store/PopularCategories";
import TopPhonesBanner from "@/app/components/user components/Store/TopPhones&Tablets";
import Filters from "@/app/components/user components/Store/Filters";
// import { useState } from "react";
import { FaFilter, FaTimes } from "react-icons/fa";

export default function ProductsLayout({ children }) {
  // const [filtersOpen, setFiltersOpen] = useState(false);

  return (
    <div>
      <TopPhonesBanner />
      <PopularCategories />

      {/* Mobile filter toggle button */}
      <div className="md:hidden flex justify-end px-4 mt-3">
        <button
          // onClick={() => setFiltersOpen(!filtersOpen)}
          className="flex items-center gap-2 bg-[#01A49E] text-white px-4 py-2 rounded-lg text-sm font-medium"
        >
          {/* {filtersOpen ? <FaTimes /> : <FaFilter />}
          {filtersOpen ? "Close Filters" : "Filters"} */}
        </button>
      </div>

      {/* Products & Filters */}
      <div className="max-w-7xl mx-auto rounded-md bg-white mt-3 px-4 py-6 md:px-6 md:py-8">
        <div className="flex flex-col md:flex-row gap-6 md:gap-10 lg:gap-16">
          {/* Filters sidebar */}
          <aside
  className={`
    fixed md:static top-0 left-0 z-50
    h-full md:h-auto
    bg-white
    w-72 md:w-56 lg:w-64
    transition-transform duration-300
   
    md:translate-x-0
  `}
>
  <Filters />
</aside>

          {/* Products */}
          <div className="flex-1 min-w-0">{children}</div>
        </div>
      </div>
    </div>
  );
}